from typing import Any, Dict, List, Tuple


class GameState:
    def __init__(self) -> None:
        self._lock = threading.Lock()
        self._start_time = time.time()
        self._players: List[Dict[str, Any]] = [
            {"id": 1, "name": "Alpha", "score": 12, "ping": 34, "team": "red"},
            {"id": 2, "name": "Bravo", "score": 19, "ping": 42, "team": "blue"},
            {"id": 3, "name": "Charlie", "score": 7, "ping": 55, "team": "red"},
            {"id": 4, "name": "Delta", "score": 25, "ping": 29, "team": "blue"},
        ]
        self._state: Dict[str, Any] = {
            "server_name": "Example Game Server",
            "map": "arena_01",
            "mode": "team_deathmatch",
            "version": "1.0.0",
            "max_players": 64,
            "tick_rate": 60,
            "round": 3,
            "round_time_remaining": 412,
            "teams": {
                "red": {"score": 48, "players": 2},
                "blue": {"score": 44, "players": 2},
            },
            "motd": "Welcome to the server browser demo",
        }

    def snapshot(self) -> Dict[str, Any]:
        with self._lock:
            uptime = int(time.time() - self._start_time)
            players = [dict(p) for p in self._players]
            state = json.loads(json.dumps(self._state))
            state["uptime"] = uptime
            state["player_count"] = len(players)
            return {"status": "ok", "game_state": state, "players": players}

    def simulate(self) -> None:
        while True:
            time.sleep(5)
            with self._lock:
                self._state["round_time_remaining"] = max(0, self._state["round_time_remaining"] - 5)
                for p in self._players:
                    p["score"] += 1
                    p["ping"] = max(10, min(150, p["ping"] + (1 if p["id"] % 2 == 0 else -1)))
                self._state["teams"]["red"]["score"] += 1
                self._state["teams"]["blue"]["score"] += 1
                if self._state["round_time_remaining"] == 0:
                    self._state["round"] += 1
                    self._state["round_time_remaining"] = 600


class UDPGameServer:
    def __init__(self, host: str, port: int, state: GameState) -> None:
        self.host = host
        self.port = port
        self.state = state
        self.running = False
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))

    def build_status_response(self) -> bytes:
        payload = self.state.snapshot()
        data = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        return data

    def handle_packet(self, data: bytes, addr: Tuple[str, int]) -> None:
        msg = data.strip()
        if msg in (b"status", b"STATUS", b"getstatus", b"GETSTATUS", b"/status"):
            response = self.build_status_response()
            self.sock.sendto(response, addr)
        elif msg in (b"ping", b"PING"):
            self.sock.sendto(b"pong", addr)
        else:
            err = json.dumps({"status": "error", "error": "unknown_query"}).encode("utf-8")
            self.sock.sendto(err, addr)

    def serve_forever(self) -> None:
        self.running = True
        while self.running:
            try:
                data, addr = self.sock.recvfrom(65535)
                self.handle_packet(data, addr)
            except OSError:
                break

    def shutdown(self) -> None:
        self.running = False
        try:
            self.sock.close()
        except OSError:
            pass


